"use client";

import { Flex, Switch, Title } from "@julien-wiegandt/open-ui";
import { Usage } from "../components/usage";

import { useState } from "react";

export const Switchs = () => {
  const [on, setOn] = useState(false);
  const [primary, setPrimary] = useState(true);
  const [secondary, setSecondary] = useState(true);
  const [defaultColor, setDefaultColor] = useState(true);
  const [error, setError] = useState(true);
  const [custom, setCustom] = useState(true);

  return (
    <Flex gap={4}>
      <Title level={2}>Switch</Title>

      <Usage
        title="base"
        components={
          <>
            <Switch />
          </>
        }
        orientation="horizontal"
        onCopy={() => navigator.clipboard.writeText(`<Switch />`)}
      />

      <Usage
        title="colors"
        components={
          <>
            <Switch
              color="primary"
              value={primary}
              onChange={(isOn) => setPrimary(isOn)}
            />
            <Switch
              color="secondary"
              value={secondary}
              onChange={(isOn) => setSecondary(isOn)}
            />
            <Switch
              color="default"
              value={defaultColor}
              onChange={(isOn) => setDefaultColor(isOn)}
            />
            <Switch
              color="error"
              value={error}
              onChange={(isOn) => setError(isOn)}
            />
            <Switch
              color="#08d2bbff"
              value={custom}
              onChange={(isOn) => setCustom(isOn)}
            />
          </>
        }
        orientation="horizontal"
        onCopy={() =>
          navigator.clipboard.writeText(`<Switch color="primary" />`)
        }
      />

      <Usage
        title="sizes"
        components={
          <>
            <Switch size={32} />
            <Switch size={48} />
            <Switch size={64} />
          </>
        }
        orientation="horizontal"
        onCopy={() => navigator.clipboard.writeText(`<Switch size={48} />`)}
      />

      <Usage
        title="controlled"
        components={
          <>
            <Switch value={on} onChange={(isOn) => setOn(isOn)} />
          </>
        }
        orientation="horizontal"
        onCopy={() =>
          navigator.clipboard.writeText(
            `<Switch value={on} onChange={(isOn) => setOn(isOn)} />`,
          )
        }
      />
    </Flex>
  );
};
