"use client";

import { forwardRef } from "react";
import { useTheme } from "styled-components";
import { useResponsive } from "../../hooks/use-responsive";
import type { Color } from "../../theme/types";
import { Button } from "../button";
import { Flex, type FlexProps } from "../flex";
import { Text } from "../text";
import { resolveColor } from "../utils/resolve-color";
import { StyledToast } from "./style";

/**
 * TODO:
 * - make children/custom toast component available
 */

export type ToastProps = {
  id: string;
  color?: Color | string;
  title?: string;
  icon?: React.ReactNode;
  duration?: number;
  children?: React.ReactNode;
  style?: React.CSSProperties;
  data?: any;
  onClose?: () => void;
} & FlexProps &
  React.HTMLAttributes<HTMLDivElement>;

export const Toast = forwardRef<HTMLDivElement, Omit<ToastProps, "id">>(
  ({ children, style, ...props }, ref) => {
    const theme = useTheme();
    const { isMobile } = useResponsive();

    return (
      <StyledToast
        ref={ref}
        p={0.5}
        elevation={3}
        {...props}
        style={{
          ...style,
        }}
      >
        {props.onClose && (
          <Button
            size="sm"
            variant="text"
            color="default"
            starticon={
              <svg
                xmlns="http://www.w3.org/2000/svg"
                width="16"
                height="16"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              >
                <path d="M18 6 6 18" />
                <path d="m6 6 12 12" />
              </svg>
            }
            onClick={props.onClose}
            style={{
              position: "absolute",
              top: "0px",
              right: "0px",
              cursor: "pointer",
            }}
          />
        )}
        {children}
        {!children && (
          <Flex
            direction="row"
            align="center"
            style={{
              minWidth: "300px",
              width: isMobile ? "calc(100vw - 40px)" : "auto",
            }}
          >
            {props.icon && (
              <Flex
                p={1.5}
                style={{
                  backgroundColor: `${resolveColor(props.color ?? "default", theme).light}44`,
                }}
              >
                {props.icon}
              </Flex>
            )}
            {props.title && (
              <Text size="14" px={1.5} py={props.icon ? 0 : 1.5}>
                {props.title}
              </Text>
            )}
          </Flex>
        )}
      </StyledToast>
    );
  },
);

Toast.displayName = "Toast";
